import React from 'react';
import { useOrderContext } from '../../Cart_Page/contextAPI/OrderCartContext';
import CartItemCard from './Card'; 
import '../style/CartPage.css';

const CartPage = () => {
    const { setOrder ,order } = useOrderContext();

    setOrder((prev) => {
        const temp = localStorage.getItem('order')
    })

    const handlePayment = ( ) => {
        localStorage.setItem('order',JSON.stringify(order));
    }

    const totalCartAmount = Object.values(order).reduce((total, item) => {
        return total + (item.price * item.quantity);
    }, 0);

    return (
        <div className="cart-page">
            <h2>Your Cart</h2>
            <div className="cart-items">
                {Object.keys(order).length === 0 ? (
                    <p>Your cart is empty</p>
                ) : (
                    Object.values(order).map(item => (
                        <CartItemCard 
                            key={item._id}
                            name={item.item}
                            description={item.discription}
                            price={item.price}
                            quantity={item.quantity}
                            // image={item.image} // Pass the image URL here
                        />
                    ))
                )}
            </div>
            <div className="cart-summary">
                <p>Total Amount: ${totalCartAmount.toFixed(2)}</p>
                <button onClick={handlePayment} className="checkout-button">
                    Proceed to Payment
                </button>
            </div>
        </div>
    );
};

export default CartPage;
